#include<bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=3e3+5;
int n,m,fir[maxn],dis1[maxn],dis2[maxn],dis3[maxn],s1,t1,s2,t2,ans=-1;
queue<int> q;
struct node{
	int to,nxt;
}e[maxn<<1];
void add(int a,int b,int p) {
	e[p]=(node) {
		b,fir[a]
	};
	fir[a]=p;
}
void bfs(int s,int* dis) {
	for(int i=1; i<=n; i++)dis[i]=INT_MAX;
	q.push(s);
	dis[s]=0;
	while(!q.empty()) {
		int x=q.front();
		q.pop();
		for(int i=fir[x]; i; i=e[i].nxt) {
			int h=e[i].to;
			if(dis[h]==INT_MAX) {
				q.push(h);
				dis[h]=dis[x]+1;
			}
		}
	}
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1,x,y; i<=m; i++) {
		cin>>x>>y;
		add(x,y,i);
		add(y,x,i+m);
	}
	cin>>s1>>t1>>s2>>t2;
	bfs(s1,dis2);
	bfs(s1,dis3);
	for(int i=1;i<=n;i++){
		if(dis1[i]+dis2[i]<=t1&&dis1[i]+dis3[i]<=t2){
			ans=max(ans,m-(dis1[i]+dis2[i]+dis3[i]));
		}
	}
	cout<<ans;
	return 0;
}
